// Defining an enum type
public enum Season {
    SPRING, SUMMER, AUTUMN, WINTER
}

// Usage
public class Main {
    public static void main(String[] args) {
        Season s = Season.SPRING;
        System.out.println(s);          // SPRING
        System.out.println(s.name());   // SPRING
        System.out.println(s.ordinal());// 0 (index based on definition order)

        // values() — array of all enum constants
        for (Season season : Season.values()) {
            System.out.println(season);
        }

        // valueOf() — convert from String
        Season w = Season.valueOf("WINTER");
        System.out.println(w); // WINTER
        // Season.valueOf("spring"); → IllegalArgumentException
    }
}

// Main class definition
public class Main {
    // main method definition
    public static void main(String[] args) {
        Season s = Season.AUTUMN;

        // switch statement: use only the enum constant name in case (no type name)
        // Branching based on the value
        switch (s) {
            case SPRING:
                System.out.println("Spring");
                break;
            case SUMMER:
                System.out.println("Summer");
                break;
            case AUTUMN:
                System.out.println("Autumn");
                break;
            case WINTER:
                System.out.println("Winter");
                break;
        }
        // Output: Autumn

        // Comparison with == (recommended)
        // Conditional branching
        if (s == Season.AUTUMN) {
            System.out.println("Season of autumn leaves");
        }
    }
}

