// Main class definition
public class Main {
    // main method definition
    public static void main(String[] args) {
        // Variable declaration and initialization
        int day = 3;

        // Traditional switch statement
        String name1;
        // Branching based on the value
        switch (day) {
            case 1: name1 = "Mon"; break;
            case 2: name1 = "Tue"; break;
            case 3: name1 = "Wed"; break;
            default: name1 = "?"; break;
        }

        // Java 14+ switch expression (arrow syntax)
        // Switch expression definition
        String name2 = switch (day) {
            case 1 -> "Mon";
            case 2 -> "Tue";
            case 3 -> "Wed";
            default -> "?";
        };
        // ↑ Switch expression requires a semicolon

        System.out.println(name2); // Wed

        // Multiple case values separated by commas
        String type = switch (day) {
            case 1, 2, 3, 4, 5 -> "Weekday";
            case 6, 7 -> "Weekend";
            default -> "Invalid";
        };
    }
}

// Main class definition
public class Main {
    // main method definition
    public static void main(String[] args) {
        // Variable declaration and initialization
        int score = 85;

        // Block syntax + yield
        // Switch expression definition
        String grade = switch (score / 10) {
            case 10, 9 -> "A";
            case 8 -> {
                System.out.println("Good!");
                yield "B";  // Use yield to return a value inside a block
            }
            case 7 -> "C";
            default -> {
                yield "D";
            }
        };
        // Output: Good!
        System.out.println(grade); // B

        // Note: return cannot be used in arrow syntax (use yield)
        // case 8 -> { return "B"; } // Compilation error
    }
}

public class Main {
    // Traditional instanceof + cast
    static void oldStyle(Object obj) {
        if (obj instanceof String) {
            String s = (String) obj;  // Explicit cast required
            System.out.println(s.length());
        }
    }

    // Java 16+ Pattern Matching
    static void newStyle(Object obj) {
        if (obj instanceof String s) {  // Type check + variable binding
            System.out.println(s.length()); // s is available as String type
        }

        // Combination with && (be careful with scope)
        if (obj instanceof String s && s.length() > 3) {
            System.out.println("Long string: " + s);
        }

        // Cannot be used with || (compilation error)
        // if (obj instanceof String s || s.isEmpty()) { } // NG
    }

    // Scope of pattern variables
    static void scopeExample(Object obj) {
        if (!(obj instanceof String s)) {
            return; // s cannot be used here
        }
        // s can be used here (flow scoping)
        System.out.println(s.toUpperCase());
    }
}

