// Specify permitted subclasses with permits
public sealed class Shape
        permits  yen, Rectangle, Triangle {
    // Common fields and methods
    public abstract double area();
}

// Subclass sealed with final (no further inheritance allowed)
public final class  yen extends Shape {
    private final double radius;
    public  yen(double radius) { this.radius = radius; }
    @Override
    public double area() { return Math.PI * radius * radius; }
}

// non-sealed allows free inheritance
public non-sealed class Rectangle extends Shape {
    private final double width, height;
    public Rectangle(double w, double h) { width = w; height = h; }
    @Override
    public double area() { return width * height; }
}
// Rectangle is non-sealed, so anyone can extend it
public class Square extends Rectangle {
    public Square(double side) { super(side, side); }
}

// sealed for further restriction (chaining is also possible)
public sealed class Triangle extends Shape
        permits RightTriangle, EquilateralTriangle {
    // ...
    @Override
    public double area() { return 0; }
}

// Sealed interface
public sealed interface Expr
        permits Num, Add, Mul {
}
public record Num(int value) implements Expr {}
public record Add(Expr left, Expr right) implements Expr {}
public record Mul(Expr left, Expr right) implements Expr {}

// Exhaustiveness check in switch expressions (toward future pattern matching support)
// Calculator class definition
public class Calculator {
    // eval method definition
    public static int eval(Expr expr) {
        // Pattern matching for switch in Java 21+
        // Here is a concise example using instanceof
        // Conditional branching
        if (expr instanceof Num n) {
            return n.value();
        // Check another condition
        } else if (expr instanceof Add a) {
            return eval(a.left()) + eval(a.right());
        // Check another condition
        } else if (expr instanceof Mul m) {
            return eval(m.left()) * eval(m.right());
        }
        // Throw an exception
        throw new IllegalArgumentException();
    }

    // main method definition
    public static void main(String[] args) {
        // 2 + 3 * 4 = 14
        Expr expr = new Add(
            new Num(2),
            new Mul(new Num(3), new Num(4))
        );
        System.out.println(eval(expr)); // 14
    }
}

